const body = $json.body || $json;
const message = String(body.message || '').trim();

function detectIntentFallback(text) {
  const m = text.toLowerCase();
  if (/tarief|tarieven|instaptarief|kilometertarief|wat kost|prijs per km|prijs per kilometer|nachttarief|wachttarief|minuuttarief|per km|per kilometer/.test(m)) {
    return 'tarieven';
  }
  if (/open rit|open ritten|nog bevestig|wachten op bevestig/.test(m)) return 'open_ritten';
  if (/chauffeur/.test(m) && /morgen|beschikbaar|vrij/.test(m)) return 'vrije_chauffeurs_morgen';
  if (/morgen/.test(m) && /rit/.test(m)) return 'ritten_morgen';
  if (/chauffeur/.test(m) && /vandaag/.test(m) && /rit/.test(m)) return 'ritten_vandaag';
  if (/vandaag/.test(m) && /rit/.test(m)) return 'ritten_vandaag';
  if (/\b(rit|ritten)\b/.test(m) && !/tarief|tarieven|boek/.test(m)) return 'ritten_komend';
  return 'faq';
}

function extractRagSearchKeyword(text) {
  const cleaned = String(text || '').toLowerCase().replace(/[^\p{L}\p{N}\s-]/gu, ' ');
  const words = cleaned.split(/\s+/).filter((w) => w.length >= 4);
  const priority = ['contact', 'telefoon', 'email', 'mail', 'bereikbaar', 'ziekenhuis', 'luchthaven', 'rolstoel', 'schiphol', 'airport', 'vervoer', 'tarief', 'tarieven'];
  for (const term of priority) {
    if (cleaned.includes(term)) return term;
  }
  return words[0] || cleaned.trim().slice(0, 40) || String(text || '').trim();
}

function buildLiveQueryUrl() {
  const fromLaravel = String(body.laravel_live_query_url || '').trim();
  const isLocal = /localhost|127\.0\.0\.1/i.test(fromLaravel);
  if (fromLaravel && !isLocal) return fromLaravel;
  const envBase = String($env.LARAVEL_API_URL || '').trim();
  if (envBase) return envBase.replace(/\/$/, '') + '/integrations/n8n/ai-chat/live-query';
  return fromLaravel;
}

function buildRagSearchUrl() {
  const fromLaravel = String(body.laravel_rag_search_url || '').trim();
  const isLocal = /localhost|127\.0\.0\.1/i.test(fromLaravel);
  if (fromLaravel && !isLocal) return fromLaravel;
  const envBase = String($env.LARAVEL_API_URL || '').trim();
  if (envBase) return envBase.replace(/\/$/, '') + '/integrations/n8n/ai-chat/rag-search';
  return fromLaravel;
}

const intent = body.intent || detectIntentFallback(message);
const allowPublicRates = body.allowPublicRates === true || intent === 'tarieven';
const allowLiveData = body.allowLiveData === true;
const companyId = Number(body.company_id || 1) || 1;
const laravelUrl = buildLiveQueryUrl();
const urlIsLocal = /localhost|127\.0\.0\.1/i.test(laravelUrl);

return [{
  json: {
    message,
    rag_search_keyword: extractRagSearchKeyword(message),
    company_id: companyId,
    channel: body.channel || 'public',
    module: body.module || 'taxi',
    intent,
    isAdmin: body.isAdmin === true,
    allowLiveData,
    allowPublicRates,
    sql_token: body.sql_token || null,
    laravel_live_query_url: laravelUrl,
    laravel_rag_search_url: buildRagSearchUrl(),
    laravel_url_warning: urlIsLocal
      ? 'localhost is niet bereikbaar vanuit n8n. Zet AI_CHAT_LARAVEL_API_URL in Laravel of LARAVEL_API_URL in n8n Variables.'
      : null,
    payload_source: body.intent ? 'laravel' : 'n8n_fallback',
    useRag: body.useRag === true || ['faq','diensten','reserveren','annuleren','betalen','contact'].includes(intent),
    response_mode: body.response_mode || 'list'
  }
}];

