const ctx = $('Normaliseer Laravel payload').item.json;
const res = $json;

function apiErrorMessage(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (typeof payload.error === 'string') return payload.error;
  if (payload.error && typeof payload.error === 'object') {
    return payload.error.message || payload.error.description || null;
  }
  if (typeof payload.message === 'string') return payload.message;
  return null;
}

if (!ctx.sql_token) {
  return [{ json: {
    answer: 'Live tarieven vereisen een sql_token vanuit Laravel. Test via de website-chat of stuur de volledige Laravel webhook payload mee.',
    source: 'blocked',
    hint: 'payload_source=' + (ctx.payload_source || 'unknown')
  }}];
}

const apiError = apiErrorMessage(res);
if (apiError && /timeout|ECONNABORTED|ETIMEDOUT/i.test(apiError)) {
  return [{ json: {
    answer: 'Laravel live-query API reageerde niet op tijd. Lokaal: herstart Docker backend met PHP_CLI_SERVER_WORKERS=8 en `php artisan serve --no-reload`. Controleer ngrok en AI_CHAT_LARAVEL_API_URL.',
    source: 'blocked',
    error: apiError
  }}];
}

if (res.success === false || res.error) {
  return [{ json: { answer: apiError || res.error || res.message || 'Kon geen databasegegevens ophalen.', source: 'blocked' } }];
}

if (typeof res === 'string' && res.trim().startsWith('<!DOCTYPE')) {
  return [{ json: {
    answer: 'Laravel API niet bereikbaar of niet gedeployed. Controleer GET https://nexasuite.nl/integrations/n8n/ai-chat/live-query/health',
    source: 'blocked'
  }}];
}

if (typeof res.answer === 'string' && res.answer.trim() !== '') {
  return [{ json: { answer: res.answer.trim(), source: res.source || 'sql', count: res.count, intent: ctx.intent } }];
}

if (res.summary && typeof res.summary === 'object' && res.summary.total_amount !== undefined) {
  const amount = Number(res.summary.total_amount || 0).toLocaleString('nl-NL', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const rideCount = res.summary.ride_count || 0;
  const date = res.summary.date || '';
  return [{ json: {
    answer: `Verwachte omzet op ${date}: €${amount} (${rideCount} ritten).`,
    source: res.source || 'sql',
    count: rideCount,
    intent: ctx.intent,
  } }];
}

const rows = Array.isArray(res.rows) ? res.rows : [];
if (res.response_mode === 'count') {
  const total = res.count ?? rows.length;
  const countAnswers = {
    ritten_vandaag: total === 1 ? 'Er staat vandaag 1 rit gepland.' : `Er staan vandaag ${total} ritten gepland.`,
    ritten_morgen: total === 1 ? 'Er staat morgen 1 rit gepland.' : `Er staan morgen ${total} ritten gepland.`,
  };
  return [{ json: {
    answer: countAnswers[ctx.intent] || (total === 1 ? 'Er is 1 resultaat.' : `Er zijn ${total} resultaten.`),
    source: res.source || 'sql',
    count: total,
    intent: ctx.intent,
  } }];
}
if (!rows.length) {
  const emptyHints = {
    ritten_vandaag: 'Er zijn vandaag geen ritten gepland voor dit bedrijf.',
    ritten_morgen: 'Er staan morgen geen ritten gepland voor dit bedrijf.',
    ritten_komend: 'Er staan geen komende ritten gepland voor dit bedrijf.',
    open_ritten: 'Er zijn geen open ritten gevonden voor dit bedrijf.',
  };
  return [{ json: {
    answer: emptyHints[ctx.intent] || 'Geen resultaten gevonden in de Nexa Taxi database voor dit bedrijf.',
    source: res.source || 'sql',
    count: 0,
    intent: ctx.intent,
  } }];
}

function pick(row, ...keys) {
  for (const key of keys) {
    const value = row?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return String(value).trim();
    }
  }
  return '';
}

function formatPickupTime(value) {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleString('nl-NL', {
    day: 'numeric',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

const statusLabels = {
  draft: 'Concept',
  quoted: 'Offerte',
  pending_dispatch: 'Wacht op chauffeur',
  offered: 'Aangeboden',
  accepted: 'Geaccepteerd',
  assigned: 'Toegewezen',
  completed: 'Voltooid',
  cancelled: 'Geannuleerd',
  pending_payment: 'Wacht op betaling',
};

const total = res.count ?? rows.length;
const intro = total === 1 ? 'Er staat 1 rit gepland:' : `Er staan ${total} ritten gepland:`;

const entries = rows.map((row, index) => {
  const rideId = pick(row, 'id');
  const customer = pick(row, 'customer_name', 'klant_naam');
  const driver = pick(row, 'driver_name', 'chauffeur_naam');
  const vehicle = pick(row, 'vehicle_name', 'voertuig_naam');
  const pickup = pick(row, 'pickup_address', 'pickup_adres');
  const dropoff = pick(row, 'dropoff_address', 'dropoff_adres');
  const pickupTime = formatPickupTime(pick(row, 'pickup_at', 'pickup_tijd'));
  const status = pick(row, 'status_label') || statusLabels[pick(row, 'status')] || pick(row, 'status');
  const label = customer || (rideId ? `Rit #${rideId}` : `Rit ${index + 1}`);
  const lines = [`${index + 1}. ${label}${rideId && customer ? ` (#${rideId})` : ''}`];
  if (driver) lines.push(`   Chauffeur: ${driver}`);
  if (vehicle) lines.push(`   Voertuig: ${vehicle}`);
  if (pickup) lines.push(`   Van: ${pickup}`);
  if (dropoff) lines.push(`   Naar: ${dropoff}`);
  if (pickupTime) lines.push(`   Ophaaltijd: ${pickupTime}`);
  if (status) lines.push(`   Status: ${status}`);
  return lines.join('\n');
});

return [{ json: {
  answer: [intro, ...entries].join('\n\n'),
  count: total,
  source: res.source || 'sql',
  intent: ctx.intent,
} }];

return [{
  json: {
    answer: 'Daar kan ik je helaas geen informatie over geven. Stel je vraag gerust op een andere manier, of neem contact met ons op.',
    source: 'denied'
  }
}];
